#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int cnt[31] = {0};
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            for(int b=0;b<31;b++) if((x>>b) & 1) cnt[b]++;
        }
        int ans = 0;
        for(int b=0;b<31;b++) if(cnt[b]>=2) ans |= (1<<b);
        printf("%d\n", ans);
    }
    return 0;
}

