import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        cnt = [0]*31
        for _ in range(N):
            x = next(it)
            b = 0
            while x:
                if x & 1:
                    cnt[b] += 1
                x >>= 1
                b += 1
        ans = 0
        for b in range(31):
            if cnt[b] >= 2:
                ans |= (1 << b)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

